'use client'

/**
 * CetakKKModal — Preview & cetak Kartu Keluarga Sementara
 *
 * Layout mengikuti format KK resmi (referensi Kemendagri):
 * - Landscape A4 (297mm × 210mm), 1 halaman untuk ≤10 anggota
 * - Header: Garuda Pancasila + KARTU KELUARGA (SEMENTARA) + No. KK
 * - Baris info: Nama KK, Alamat, RT/RW, Kode Pos | Desa, Kecamatan, Kabupaten, Provinsi
 * - Tabel Atas  : No | Nama | NIK | JK | Tempat Lahir | Tgl Lahir | Agama | Pendidikan | Pekerjaan | Gol. Darah
 * - Tabel Bawah : No | Status Kawin | Tgl Kawin | Hub. Keluarga | Kewarganegaraan | No. Paspor | No. KITAP | Nama Ayah | Nama Ibu
 */

import { useRef } from 'react'
import { X, Printer } from 'lucide-react'
import type { Penduduk } from '@/types'
import type { ConfigWilayah } from '@/types'
import { formatTanggalLahir } from '@/lib/dateUtils'

// Garuda Pancasila B&W — embedded base64 agar tidak butuh server request saat cetak
const GARUDA_B64 = ''

interface Props {
  noKk: string
  anggota: Penduduk[]   // sudah diurutkan: KK → Istri → Anak → dst
  wilayah: ConfigWilayah
  onClose: () => void
}

function formatTanggalCetak(date: Date): string {
  return date.toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' })
}

function getKepalaKeluarga(anggota: Penduduk[]): Penduduk | undefined {
  return anggota.find((p) => p.hubungan_keluarga === 'Kepala Keluarga')
}

export function CetakKKModal({ noKk, anggota, wilayah, onClose }: Props) {
  const printRef = useRef<HTMLDivElement>(null)
  const kk = getKepalaKeluarga(anggota)
  const tanggalCetak = formatTanggalCetak(new Date())

  const rows = anggota.slice(0, 10)
  const emptyRows = Array.from({ length: Math.max(0, 10 - rows.length) })

  const kodePos = wilayah.kode_pos ?? '68284'

  function handleCetak() {
    const printContent = printRef.current
    if (!printContent) return

    const printWindow = window.open('', '_blank', 'width=1123,height=794')
    if (!printWindow) {
      alert('Pop-up diblokir browser. Izinkan pop-up untuk halaman ini.')
      return
    }

    printWindow.document.write(`
<!DOCTYPE html>
<html lang="id">
<head>
  <meta charset="UTF-8" />
  <title>KK Sementara — ${noKk}</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    @page {
      size: A4 landscape;
      margin: 0;
    }
    html, body {
      width: 297mm;
      height: 210mm;
      font-family: 'Times New Roman', Times, serif;
      font-size: 8.5pt;
      background: white;
      color: black;
    }
    .page {
      width: 297mm;
      height: 210mm;
      padding: 5mm 6mm 4mm 6mm;
      overflow: hidden;
    }
    /* ── HEADER ── */
    .kk-header {
      display: flex;
      align-items: flex-start;
      margin-bottom: 1.5mm;
    }
    .garuda-wrap {
      width: 24mm;
      flex-shrink: 0;
      display: flex;
      flex-direction: column;
      align-items: center;
      padding-top: 1mm;
    }
    .garuda-wrap img {
      width: 20mm;
      height: auto;
      display: block;
    }
    .garuda-wrap .rep-ind {
      font-size: 5.5pt;
      font-weight: bold;
      text-align: center;
      margin-top: 0.5mm;
      letter-spacing: 0.2px;
      line-height: 1.2;
    }
    .judul-center {
      flex: 1;
      text-align: center;
      padding-top: 0;
    }
    .judul-kk {
      font-size: 17pt;
      font-weight: bold;
      letter-spacing: 2px;
      line-height: 1.1;
    }
    .judul-sementara {
      font-size: 10pt;
      font-weight: bold;
      letter-spacing: 1.5px;
      line-height: 1.2;
    }
    .nomor-kk {
      font-size: 13pt;
      font-weight: bold;
      letter-spacing: 1px;
      margin-top: 1mm;
      font-family: 'Courier New', monospace;
    }
    .info-kanan {
      width: 72mm;
      flex-shrink: 0;
      padding-top: 1mm;
    }
    .info-row {
      display: flex;
      font-size: 7.5pt;
      line-height: 1.55;
    }
    .info-label { width: 29mm; }
    .info-colon { width: 4mm; text-align: center; }
    .info-val   { flex: 1; font-weight: bold; }
    /* ── DATA BARIS ── */
    .data-section {
      display: flex;
      gap: 3mm;
      margin-bottom: 1.5mm;
      border-top: 0.5pt solid #000;
      border-bottom: 0.5pt solid #000;
      padding: 1.2mm 0;
    }
    .data-kiri { flex: 1; }
    .data-kanan { width: 72mm; flex-shrink: 0; }
    .drow { display: flex; font-size: 7.5pt; line-height: 1.55; }
    .drow-label { width: 29mm; }
    .drow-colon { width: 4mm; text-align: center; }
    .drow-val   { flex: 1; font-weight: bold; }
    /* ── TABEL ── */
    table {
      width: 100%;
      border-collapse: collapse;
      margin-bottom: 1mm;
    }
    th, td {
      border: 0.4pt solid #000;
      padding: 0.7mm 1mm;
      vertical-align: middle;
      line-height: 1.25;
      font-size: 7pt;
    }
    th {
      background: #cccccc;
      font-weight: bold;
      text-align: center;
      font-size: 6.5pt;
    }
    td { text-align: center; }
    td.left { text-align: left; }
    .col-no   { width: 5mm; }
    .col-nama { min-width: 35mm; max-width: 38mm; text-align: left; }
    .col-nik  { width: 26mm; font-family: 'Courier New', monospace; font-size: 6.5pt; }
    .col-jk   { width: 7mm; }
    .col-tl   { width: 20mm; }
    .col-ttl  { width: 17mm; }
    .col-agama { width: 14mm; }
    .col-pend  { width: 22mm; }
    .col-pek   { min-width: 24mm; max-width: 28mm; text-align: left; }
    .col-gol   { width: 8mm; }
    .col-statkawin { width: 17mm; }
    .col-tglkawin  { width: 14mm; }
    .col-hub       { width: 22mm; }
    .col-wn        { width: 12mm; }
    .col-paspor    { width: 14mm; }
    .col-kitap     { width: 14mm; }
    .col-ayah      { min-width: 28mm; max-width: 32mm; text-align: left; }
    .col-ibu       { min-width: 28mm; max-width: 32mm; text-align: left; }
    tr.dr td { height: 6.5mm; }
    /* ── FOOTER ── */
    .footer {
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
      margin-top: 1.5mm;
    }
    .ttd-blok { text-align: center; }
    .ttd-tgl  { font-size: 8pt; }
    .ttd-tgl-box {
      display: inline-block;
      border: 0.7pt solid #000;
      padding: 0.5mm 2mm;
      margin-left: 1.5mm;
      font-weight: bold;
      font-size: 8pt;
    }
    .ttd-label { font-size: 8pt; font-weight: bold; text-transform: uppercase; }
    .ttd-lokasi { font-size: 7pt; }
    .ttd-nama {
      font-weight: bold;
      font-size: 8.5pt;
      margin-top: 12mm;
      border-bottom: 0.5pt solid #000;
      padding-bottom: 0.5mm;
      min-width: 50mm;
    }
    .ttd-nip { font-size: 7.5pt; margin-top: 0.5mm; }
    .ttd-sub { font-size: 7pt; margin-top: 0.5mm; }
    .disclaimer {
      text-align: center;
      font-size: 6.5pt;
      margin-top: 1mm;
      padding-top: 1mm;
      border-top: 0.5pt solid #888;
      color: #333;
      font-style: italic;
    }
    @media print {
      html, body { margin: 0; }
    }
  </style>
</head>
<body>
<div class="page">
  ${printContent.innerHTML}
</div>
</body>
</html>`)

    printWindow.document.close()
    printWindow.focus()
    setTimeout(() => { printWindow.print() }, 350)
  }

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
      <div className="bg-[#0d1424] border border-white/[0.08] rounded-2xl flex flex-col w-full max-w-2xl max-h-[92dvh]">

        {/* Header modal */}
        <div className="flex items-center justify-between px-5 py-4 border-b border-white/[0.06] shrink-0">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 rounded-xl bg-sky-500/15 border border-sky-500/20 flex items-center justify-center">
              <Printer size={17} className="text-sky-400" />
            </div>
            <div>
              <p className="font-semibold text-slate-100 text-sm">Cetak KK Sementara</p>
              <p className="text-xs text-slate-500 font-mono mt-0.5">No. KK: {noKk}</p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="p-1.5 rounded-lg text-slate-500 hover:text-slate-300 hover:bg-white/5 transition-colors"
          >
            <X size={15} />
          </button>
        </div>

        {/* Info */}
        <div className="flex-1 min-h-0 overflow-y-auto px-5 py-4">
          {!wilayah.nama_kades && (
            <div className="mb-4 flex items-start gap-2.5 px-3 py-2.5 rounded-xl bg-amber-500/10 border border-amber-500/20">
              <span className="text-amber-400 text-sm shrink-0">⚠</span>
              <p className="text-sm text-amber-300">
                Nama Kepala Desa belum diisi. Pergi ke{' '}
                <span className="font-semibold">Pengaturan → Informasi Wilayah</span>{' '}
                untuk mengisi data Kepala Desa sebelum mencetak.
              </p>
            </div>
          )}

          <div className="grid grid-cols-2 gap-2 mb-4">
            {[
              ['Kepala Keluarga', kk?.nama_lengkap ?? '—'],
              ['Jumlah Anggota', `${anggota.length} orang`],
              ['Desa', `Desa ${wilayah.desa}`],
              ['Tanggal Cetak', tanggalCetak],
            ].map(([label, val]) => (
              <div key={label} className="bg-white/[0.03] border border-white/[0.06] rounded-xl px-3 py-2">
                <p className="text-xs text-slate-500">{label}</p>
                <p className="text-sm font-medium text-slate-200 mt-0.5">{val}</p>
              </div>
            ))}
          </div>

          {anggota.length > 10 && (
            <p className="text-xs text-amber-400 mb-3">
              KK ini memiliki {anggota.length} anggota. Format KK standar hanya menampilkan 10 baris pertama.
            </p>
          )}

          <p className="text-xs text-slate-500 mb-4">
            Dokumen akan dibuka di tab baru untuk dicetak atau disimpan sebagai PDF.
            Pastikan ukuran kertas diatur ke <span className="text-slate-300 font-medium">A4 Landscape</span> di dialog cetak browser.
          </p>
        </div>

        {/* Tombol aksi */}
        <div className="flex items-center gap-2.5 px-5 py-4 border-t border-white/[0.06] shrink-0">
          <button
            onClick={onClose}
            className="flex-1 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-slate-400 hover:text-slate-200 text-sm font-medium transition-colors"
          >
            Batal
          </button>
          <button
            onClick={handleCetak}
            disabled={!wilayah.nama_kades}
            className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-sky-500 hover:bg-sky-400 disabled:bg-sky-500/30 disabled:cursor-not-allowed text-white text-sm font-semibold transition-colors"
          >
            <Printer size={15} />
            Cetak / Simpan PDF
          </button>
        </div>
      </div>

      {/* Konten HTML untuk dicetak */}
      <div className="hidden">
        <div ref={printRef}>
          {/* ── HEADER ── */}
          <div className="kk-header">
            {/* Garuda */}
            <div className="garuda-wrap">
              <img src={`data:image/png;base64,${GARUDA_B64}`} alt="Garuda Pancasila" />
              <div className="rep-ind">REPUBLIK<br/>INDONESIA</div>
            </div>
            {/* Judul tengah */}
            <div className="judul-center">
              <div className="judul-kk">KARTU KELUARGA</div>
              <div className="judul-sementara">SEMENTARA</div>
              <div className="nomor-kk">No. &nbsp;{noKk}</div>
            </div>
            {/* Info kanan */}
            <div className="info-kanan">
              <div className="info-row">
                <span className="info-label">Desa/Kelurahan</span>
                <span className="info-colon">:</span>
                <span className="info-val">{wilayah.desa}</span>
              </div>
              <div className="info-row">
                <span className="info-label">Kecamatan</span>
                <span className="info-colon">:</span>
                <span className="info-val">{wilayah.kecamatan}</span>
              </div>
              <div className="info-row">
                <span className="info-label">Kabupaten/Kota</span>
                <span className="info-colon">:</span>
                <span className="info-val">{wilayah.kabupaten}</span>
              </div>
              <div className="info-row">
                <span className="info-label">Provinsi</span>
                <span className="info-colon">:</span>
                <span className="info-val">{wilayah.provinsi}</span>
              </div>
            </div>
          </div>

          {/* ── BARIS DATA KK ── */}
          <div className="data-section">
            <div className="data-kiri">
              <div className="drow">
                <span className="drow-label">Nama Kepala Keluarga</span>
                <span className="drow-colon">:</span>
                <span className="drow-val">{kk?.nama_lengkap ?? '—'}</span>
              </div>
              <div className="drow">
                <span className="drow-label">Alamat</span>
                <span className="drow-colon">:</span>
                <span className="drow-val">{kk?.alamat ?? '—'}</span>
              </div>
              <div className="drow">
                <span className="drow-label">RT/RW</span>
                <span className="drow-colon">:</span>
                <span className="drow-val">{kk ? `${kk.rt}/${kk.rw ?? '—'}` : '—'}</span>
              </div>
              <div className="drow">
                <span className="drow-label">Kode Pos</span>
                <span className="drow-colon">:</span>
                <span className="drow-val">{kodePos}</span>
              </div>
            </div>
          </div>

          {/* ── TABEL ATAS ── */}
          <table>
            <thead>
              <tr>
                <th className="col-no">No</th>
                <th className="col-nama">Nama Lengkap</th>
                <th className="col-nik">NIK</th>
                <th className="col-jk">Jenis<br/>Kelamin</th>
                <th className="col-tl">Tempat Lahir</th>
                <th className="col-ttl">Tanggal<br/>Lahir</th>
                <th className="col-agama">Agama</th>
                <th className="col-pend">Pendidikan</th>
                <th className="col-pek">Jenis Pekerjaan</th>
                <th className="col-gol">Gol.<br/>Darah</th>
              </tr>
              <tr>
                {['','(1)','(2)','(3)','(4)','(5)','(6)','(7)','(8)','(9)'].map((n,i) => (
                  <th key={i}>{n}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {rows.map((p, i) => (
                <tr key={p.id} className="dr">
                  <td>{i + 1}</td>
                  <td className="left">{p.nama_lengkap}</td>
                  <td className="col-nik">{p.nik || '-'}</td>
                  <td>{p.jenis_kelamin === 'Laki-laki' ? 'L' : 'P'}</td>
                  <td>{p.tempat_lahir || '-'}</td>
                  <td>{p.tanggal_lahir ? formatTanggalLahir(p.tanggal_lahir) : '-'}</td>
                  <td>{p.agama || '-'}</td>
                  <td>{p.pendidikan || '-'}</td>
                  <td className="left">{p.pekerjaan || '-'}</td>
                  <td>{p.golongan_darah || '-'}</td>
                </tr>
              ))}
              {emptyRows.map((_, i) => (
                <tr key={`ea${i}`} className="dr">
                  <td>{rows.length + i + 1}</td>
                  <td>-</td><td>-</td><td></td><td></td><td></td><td></td><td></td><td></td><td></td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* ── TABEL BAWAH ── */}
          <table>
            <thead>
              <tr>
                <th className="col-no">No</th>
                <th className="col-statkawin">Status<br/>Perkawinan</th>
                <th className="col-tglkawin">Tanggal<br/>Perkawinan/<br/>Perceraian</th>
                <th className="col-hub">Status Hubungan<br/>Dalam Keluarga</th>
                <th className="col-wn">Kewarganega-<br/>raan</th>
                <th className="col-paspor">No. Paspor</th>
                <th className="col-kitap">No. KITAP</th>
                <th className="col-ayah">Nama Ayah</th>
                <th className="col-ibu">Nama Ibu</th>
              </tr>
              <tr>
                {['','(10)','(11)','(12)','(13)','(14)','(15)','(16)','(17)'].map((n,i) => (
                  <th key={i}>{n}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {rows.map((p, i) => (
                <tr key={p.id} className="dr">
                  <td>{i + 1}</td>
                  <td>{p.status_perkawinan || '-'}</td>
                  <td>-</td>
                  <td>{p.hubungan_keluarga || '-'}</td>
                  <td>WNI</td>
                  <td>-</td>
                  <td>-</td>
                  <td className="left">{p.nama_ayah || '-'}</td>
                  <td className="left">{p.nama_ibu || '-'}</td>
                </tr>
              ))}
              {emptyRows.map((_, i) => (
                <tr key={`eb${i}`} className="dr">
                  <td>{rows.length + i + 1}</td>
                  <td>-</td><td></td><td></td><td></td><td></td><td></td><td></td><td></td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* ── FOOTER ── */}
          <div className="footer">
            {/* Kiri: tanggal */}
            <div style={{paddingTop:'1mm'}}>
              <span className="ttd-tgl">
                Dikeluarkan Tanggal:
                <span className="ttd-tgl-box">{tanggalCetak}</span>
              </span>
            </div>

            {/* Tengah: Kepala Keluarga */}
            <div className="ttd-blok" style={{textAlign:'center'}}>
              <div className="ttd-label">KEPALA KELUARGA</div>
              <div className="ttd-nama">{kk?.nama_lengkap ?? '................................'}</div>
              <div className="ttd-sub">Tanda Tangan/Cap Jempol</div>
            </div>

            {/* Kanan: Kepala Desa */}
            <div className="ttd-blok" style={{textAlign:'center'}}>
              <div className="ttd-label">{(wilayah.jabatan_kades ?? 'KEPALA DESA').toUpperCase()}</div>
              <div className="ttd-lokasi">
                DESA {(wilayah.desa ?? '').toUpperCase()}, KEC. {(wilayah.kecamatan ?? '').toUpperCase()}
              </div>
              <div className="ttd-lokasi">KAB. {(wilayah.kabupaten ?? '').toUpperCase()}</div>
              <div className="ttd-nama">{wilayah.nama_kades ?? '................................'}</div>
              {wilayah.nip_kades && (wilayah.jabatan_kades === 'Pj. Kepala Desa' || wilayah.jabatan_kades === 'Plt. Kepala Desa') && (
                <div className="ttd-nip">NIP. {wilayah.nip_kades}</div>
              )}
            </div>
          </div>

          {/* Disclaimer */}
          <div className="disclaimer">
            Dokumen ini merupakan Kartu Keluarga Sementara yang diterbitkan oleh Pemerintah Desa {wilayah.desa},
            berlaku selama Kartu Keluarga definitif masih dalam proses penerbitan di Dinas Kependudukan dan Pencatatan Sipil.
          </div>
        </div>
      </div>
    </div>
  )
}
